import React from 'react'
import { useState } from 'react'

export default function (props) {
  const name=props.item.name
  let changeStatus=()=>{
    console.log(props.item.status)
    props.turnOnOrOff(props.name,props.n ,!props.item.status)
  }
  let printI=()=>{
    if(!props.item.status)
    return <img src="/buttons/on.png" onClick={changeStatus}></img>
    else
    return <img src="/buttons/off.png" onClick={changeStatus}></img>
  }
  return (
    <div>
      <h2>{name}</h2>
      {printI()}

      
    </div>
  )
}
